+              <a href="<?php echo esc_url($account_url); ?>"><?php echo esc_html__('My account', 'printonet-theme'); ?></a>
+            <?php else : ?>
+              <a href="<?php echo esc_url($account_url); ?>"><?php echo esc_html__('Login', 'printonet-theme'); ?></a>
+              <span>/</span>
+              <a href="<?php echo esc_url($account_url); ?>"><?php echo esc_html__('Register', 'printonet-theme'); ?></a>
+            <?php endif; ?>
+          </nav>
+        </div>
+      </div>
+
+      <div class="storefront-primary-navigation printonet-hook-header__nav">
+        <div class="col-full">
+          <div class="printonet-hook-header__nav-main">
+            <?php storefront_primary_navigation(); ?>
+          </div>
+          <div class="printonet-hook-header__nav-actions">
+            <?php storefront_header_cart(); ?>
+          </div>
+        </div>
+      </div>
+    </div>
+    <?php
+}
